<template>
    <!-- pages/lottery/lottery.wxml -->
    <view class="lottery-container">
        <!-- 主体内容 -->
        <view class="main-content">
            <!-- 积分信息 -->
            <view class="points-section card">
                <view class="points-info">
                    <text class="points-label">我的积分</text>
                    <text class="points-value">{{ userPoints }}</text>
                </view>
                <text class="points-desc">每消费1元得1积分</text>
            </view>

            <!-- 转盘抽奖 -->
            <view class="lottery-section card">
                <view class="lottery-title">
                    <text class="title-text">幸运转盘</text>
                    <text class="title-desc">消耗100积分转一次</text>
                </view>

                <view class="lottery-wheel">
                    <!-- 转盘背景 -->
                    <view class="wheel-bg" :style="'transform: rotate(' + wheelRotation + 'deg);'">
                        <view :class="'prize-item prize-' + index" :style="'transform: rotate(' + index * 45 + 'deg);'" v-for="(item, index) in prizes" :key="index">
                            <view class="prize-content" :style="'transform: rotate(-' + index * 45 + 'deg);'">
                                <text class="prize-text">{{ item.name }}</text>
                            </view>
                        </view>
                    </view>

                    <!-- 转盘指针 -->
                    <view class="wheel-pointer"></view>

                    <!-- 开始按钮 -->
                    <view :class="'start-btn ' + (isSpinning ? 'spinning' : '')" @tap="startLottery">
                        <text>{{ isSpinning ? '转动中' : '开始' }}</text>
                    </view>
                </view>
            </view>

            <!-- 奖品列表 -->
            <view class="prizes-section card">
                <view class="section-title">
                    <text>奖品说明</text>
                </view>
                <view class="prizes-list">
                    <view class="prize-desc" v-for="(item, index) in prizes" :key="index">
                        <view :class="'prize-color prize-color-' + index"></view>

                        <text class="prize-name">{{ item.name }}</text>

                        <text class="prize-probability">{{ item.probability }}%</text>
                    </view>
                </view>
            </view>

            <!-- 中奖记录 -->
            <view class="records-section card" v-if="lotteryRecords.length > 0">
                <view class="section-title">
                    <text>中奖记录</text>
                </view>
                <view class="records-list">
                    <view class="record-item" v-for="(item, index) in lotteryRecords" :key="index">
                        <text class="record-time">{{ item.time }}</text>

                        <text class="record-prize">{{ item.prize }}</text>
                    </view>
                </view>
            </view>
        </view>

        <!-- 中奖弹窗 -->
        <view :class="'result-modal ' + (showResult ? 'show' : '')" @tap="hideResult">
            <view class="result-content" @tap.stop.prevent="stopPropagation">
                <view class="result-header">
                    <text class="result-title">{{ resultTitle }}</text>
                    <view class="close-result" @tap="hideResult">×</view>
                </view>
                <view class="result-body">
                    <image src="/static/images/shouye/jifen.png" class="result-icon" />
                    <text class="result-text">{{ resultText }}</text>
                </view>
                <view class="result-footer">
                    <view class="confirm-result" @tap="hideResult">确定</view>
                </view>
            </view>
        </view>
    </view>
</template>

<script>
const app = getApp();
export default {
    data() {
        return {
            userPoints: 0,
            wheelRotation: 0,
            isSpinning: false,
            showResult: false,
            resultTitle: '',
            resultText: '',
            lotteryRecords: [],
            // 奖品配置
            prizes: [
                {
                    id: 1,
                    name: '5元优惠券',
                    probability: 30
                },
                {
                    id: 2,
                    name: '谢谢参与',
                    probability: 35
                },
                {
                    id: 3,
                    name: '10元优惠券',
                    probability: 20
                },
                {
                    id: 4,
                    name: '免费奶茶',
                    probability: 10
                },
                {
                    id: 5,
                    name: '20元优惠券',
                    probability: 4
                },
                {
                    id: 6,
                    name: '谢谢参与',
                    probability: 1
                },
                {
                    id: 7,
                    name: '50积分',
                    probability: 0
                },
                {
                    id: 8,
                    name: '100积分',
                    probability: 0
                }
            ]
        };
    },
    onLoad() {
        this.loadUserPoints();
        this.loadLotteryRecords();
    },
    onShow() {
        this.loadUserPoints();
    },
    methods: {
        // 加载用户积分
        loadUserPoints() {
            if (app.globalData.isLogin) {
                const orderHistory = app.globalData.orderHistory;
                const totalSpent = orderHistory.reduce((total, order) => {
                    return total + parseFloat(order.totalPrice || 0);
                }, 0);

                // 模拟积分计算（消费1元得1积分）
                const points = Math.floor(totalSpent);
                this.setData({
                    userPoints: points
                });
            }
        },

        // 加载抽奖记录
        loadLotteryRecords() {
            const records = uni.getStorageSync('lotteryRecords') || [];
            this.setData({
                lotteryRecords: records
            });
        },

        // 开始抽奖
        startLottery() {
            if (!app.globalData.isLogin) {
                uni.showModal({
                    title: '请先登录',
                    content: '需要登录后才能参与抽奖',
                    success: (res) => {
                        if (res.confirm) {
                            uni.switchTab({
                                url: '/pages/profile/profile'
                            });
                        }
                    }
                });
                return;
            }
            if (this.userPoints < 100) {
                uni.showToast({
                    title: '积分不足',
                    icon: 'none'
                });
                return;
            }
            if (this.isSpinning) {
                return;
            }
            this.setData({
                isSpinning: true
            });

            // 扣除积分（这里只是模拟，实际应该在后端处理）
            const newPoints = this.userPoints - 100;
            this.setData({
                userPoints: newPoints
            });

            // 计算中奖结果
            const result = this.calculatePrize();
            const targetAngle = result.index * 45 + 22.5; // 每个扇形45度，指向中心
            const spinAngle = 1800 + targetAngle; // 转5圈后停在目标位置

            this.setData({
                wheelRotation: this.wheelRotation + spinAngle
            });

            // 3秒后显示结果
            setTimeout(() => {
                this.setData({
                    isSpinning: false,
                    showResult: true,
                    resultTitle: result.prize.name === '谢谢参与' ? '很遗憾' : '恭喜您',
                    resultText: result.prize.name === '谢谢参与' ? '谢谢参与，下次再来！' : `获得${result.prize.name}！`
                });

                // 记录抽奖结果
                this.addLotteryRecord(result.prize.name);
            }, 3000);
        },

        // 计算中奖结果
        calculatePrize() {
            const random = Math.random() * 100;
            let cumulative = 0;
            for (let i = 0; i < this.prizes.length; i++) {
                cumulative += this.prizes[i].probability;
                if (random <= cumulative) {
                    return {
                        index: i,
                        prize: this.prizes[i]
                    };
                }
            }

            // 默认返回谢谢参与
            return {
                index: 1,
                prize: this.prizes[1]
            };
        },

        // 添加抽奖记录
        addLotteryRecord(prizeName) {
            const record = {
                id: Date.now(),
                time: new Date().toLocaleString(),
                prize: prizeName
            };
            const records = [record, ...this.lotteryRecords].slice(0, 10); // 只保留最近10条
            this.setData({
                lotteryRecords: records
            });
            uni.setStorageSync('lotteryRecords', records);
        },

        // 隐藏结果弹窗
        hideResult() {
            this.setData({
                showResult: false
            });
        },

        // 阻止事件冒泡
        stopPropagation() {
            // 阻止事件冒泡
        },

        // 返回上一页
        goBack() {
            uni.navigateBack();
        }
    }
};
</script>
